problems.hint:
text = input()
keyword = input()
shift = sum(ord(c) for c in keyword) % 26

def enc(c, idx):
    d = 1 if idx % 2 == 0 else -1
    if c.isalpha():
        b = ord('A') if c.isupper() else ord('a')
        return chr((ord(c) - b + d * shift) % 26 + b)
    elif c.isdigit():
        return str((int(c) + d * shift) % 10)
    return c

encoded = tuple(enc(c, i) for i, c in enumerate(text))
encoded_str = ''.join(encoded)
pairs = tuple(zip(text, encoded))

freq = {}
for c in encoded:
    if c.isalpha(): freq[c] = freq.get(c, 0) + 1
freq_tuple = tuple(sorted(freq.items(),
    key=lambda x: (-x[1], x[0].lower(), 0 if x[0].isupper() else 1)))

seen = {}
for i, c in enumerate(text):
    if c not in seen:
        d = 1 if i % 2 == 0 else -1
        applied = d * shift if (c.isalpha() or c.isdigit()) else 0
        seen[c] = (c, encoded[i], applied)
encoding_table = tuple(seen[c] for c in sorted(seen.keys()))

def dec(c, idx):
    d = 1 if idx % 2 == 0 else -1
    if c.isalpha():
        b = ord('A') if c.isupper() else ord('a')
        return chr((ord(c) - b - d * shift) % 26 + b)
    elif c.isdigit():
        return str((int(c) - d * shift) % 10)
    return c

decoded = ''.join(dec(c, i) for i, c in enumerate(encoded))
print('Shift:', shift)
print('Encoded:', encoded_str)
print('Pairs:', pairs)
print('Frequency:', freq_tuple)
print('Encoding table:', encoding_table)
print('Decoded match:', decoded == text)
